    return res.status(400).json({ error: 'Invalid input', details: parsed.error.flatten() });
  }
  // use parsed.data — never req.body directly
  res.status(201).json({ id: 3, ...parsed.data });
});
```

**Key principles:** validate shape *and* length, reject unknown keys (`.strict()`), and pass the parsed object downstream — never the raw `req.body`.

